func TestContainsLccProjection(t *testing.T) {
	area := fortiblob.GeographicArea{
		WKT: "POLYGON ((-897442.359961731 -1104322.21784516,-897442.359961731 1215678.42873958,897558.002775708 1215678.42873958,897558.002775708 -1104322.21784516,-897442.359961731 -1104322.21784516))",
		SRS: "+proj=lcc +lat_1=63 +lat_2=63 +lat_0=63 +lon_0=15 +x_0=0 +y_0=0 +a=6371000 +b=6371000 +units=m +no_defs",
	}
	grid, err := New(area)
	if err != nil {
		t.Fatal(err)
	}
	ll := LatLon{Longitude: 11, Latitude: 59}
	if !grid.Contains(ll) {
		t.Errorf("should contain area %s", ll)
	}
}
